<?php
 namespace WPAICG\Chat\Storage\SaverMethods; use WPAICG\AIPKit_Providers; if (!defined('ABSPATH')) { exit; } function handle_openai_specific_settings_logic(int $botId, array $sanitized_settings): void { if (isset($sanitized_settings['provider']) && $sanitized_settings['provider'] === 'OpenAI' && isset($sanitized_settings['openai_conversation_state_enabled']) && $sanitized_settings['openai_conversation_state_enabled'] === '1') { if (class_exists(\WPAICG\AIPKit_Providers::class)) { $openai_global_settings = AIPKit_Providers::get_provider_data('OpenAI'); if (($openai_global_settings['store_conversation'] ?? '0') !== '1') { $openai_global_settings['store_conversation'] = '1'; AIPKit_Providers::save_provider_data('OpenAI', $openai_global_settings); } } } } 